mapper.select:
SELECT id, seller_id, balance, frozen_amount, total_income, total_withdraw, create_time, update_time
FROM seller_account
WHERE seller_id = #{sellerId}

mapper.update:
UPDATE seller_account
SET frozen_amount = frozen_amount - #{amount},
    update_time = NOW()
WHERE seller_id = #{sellerId}
  AND frozen_amount >= #{amount}

UPDATE seller_account
SET frozen_amount = frozen_amount - #{amount},
    balance = balance + #{amount},
    update_time = NOW()
WHERE seller_id = #{sellerId}
  AND frozen_amount >= #{amount}

UPDATE seller_account
SET balance = balance - #{amount},
    update_time = NOW()
WHERE seller_id = #{sellerId}
  AND balance >= #{amount}
